-- ============================================================
-- Migration 022: Import historical data from DATA_CS Google Sheet
--   Source: https://docs.google.com/spreadsheets/d/1nrNPpD9JF40-nMKNaCxJRf6CZk9TorTC-fGcyEHHSUA
--   Date range: 1/7/2025 -> 31/1/2026
--   3 tables -> daily_sale_bills + daily_sale_payments + daily_sale_reconcile
--   Generated: 124 Table A bills, 190 Table B merges, 184 Table C reconcile rows
-- ============================================================

BEGIN;

-- -- Table A -> daily_sale_bills (main bill list: Dailysale)
ON CONFLICT (bill_no) DO UPDATE SET
  amount = EXCLUDED.amount,
  member_code = COALESCE(EXCLUDED.member_code, daily_sale_bills.member_code),
  member_name = COALESCE(EXCLUDED.member_name, daily_sale_bills.member_name),
  branch = COALESCE(EXCLUDED.branch, daily_sale_bills.branch),
  channel = COALESCE(EXCLUDED.channel, daily_sale_bills.channel),
  recorded_by = COALESCE(EXCLUDED.recorded_by, daily_sale_bills.recorded_by),
  notes = COALESCE(EXCLUDED.notes, daily_sale_bills.notes);

-- -- Table A -> daily_sale_payments (breakdown per bill)
ON CONFLICT (bill_no) DO UPDATE SET
  cash = EXCLUDED.cash,
  transfer = EXCLUDED.transfer,
  credit_card = EXCLUDED.credit_card,
  ewallet = EXCLUDED.ewallet,
  gift_voucher = EXCLUDED.gift_voucher,
  qr_payment = EXCLUDED.qr_payment,
  commission_deduct = EXCLUDED.commission_deduct,
  arp_amount = EXCLUDED.arp_amount;

-- -- Table B -> daily_sale_bills (shipping / CheckBillOnline notes)
-- Same bill_no as Table A sometimes; UPSERT with COALESCE merges notes/channel
ON CONFLICT (bill_no) DO UPDATE SET
  notes = COALESCE(EXCLUDED.notes, daily_sale_bills.notes),
  channel = COALESCE(EXCLUDED.channel, daily_sale_bills.channel),
  member_code = COALESCE(EXCLUDED.member_code, daily_sale_bills.member_code),
  member_name = COALESCE(EXCLUDED.member_name, daily_sale_bills.member_name),
  branch = COALESCE(EXCLUDED.branch, daily_sale_bills.branch);

-- -- Table B -> daily_sale_payments (merge payment amounts)
ON CONFLICT (bill_no) DO UPDATE SET
  credit_card = GREATEST(daily_sale_payments.credit_card, EXCLUDED.credit_card),
  ewallet = GREATEST(daily_sale_payments.ewallet, EXCLUDED.ewallet),
  qr_payment = GREATEST(daily_sale_payments.qr_payment, EXCLUDED.qr_payment),
  commission_deduct = GREATEST(daily_sale_payments.commission_deduct, EXCLUDED.commission_deduct),
  arp_amount = GREATEST(daily_sale_payments.arp_amount, EXCLUDED.arp_amount);

-- -- Table C -> daily_sale_reconcile (daily signoff)
ON CONFLICT (reconcile_date, branch) DO UPDATE SET
  bill_count = EXCLUDED.bill_count,
  bill_value = EXCLUDED.bill_value,
  remaining = EXCLUDED.remaining,
  system_count = EXCLUDED.system_count,
  system_value = EXCLUDED.system_value,
  signature = COALESCE(EXCLUDED.signature, daily_sale_reconcile.signature),
  notes = COALESCE(EXCLUDED.notes, daily_sale_reconcile.notes);

COMMIT;

-- ============================================================
-- DONE
